const body = $input.first().json.body || $input.first().json;

const firstName = body.firstName || body.first_name || body.name?.split(' ')[0] || '';
const lastName = body.lastName || body.last_name || body.name?.split(' ').slice(1).join(' ') || '';
const email = (body.email || body.emailAddress || '').trim().toLowerCase();
const rawPhone = body.phone || body.phoneNumber || body.whatsapp || '';
const service = body.service || body.serviceInterest || body.inquiry_type || 'General Enquiry';
const message = body.message || body.notes || body.comment || '';
const preferredTime = body.preferredTime || body.preferred_date || '';
const source = body.source || body.utm_source || 'Website Form';

// Normalise HK phone to E.164
const digits = rawPhone.replace(/\D/g, '');
const phone = rawPhone ? (digits.startsWith('852') ? '+' + digits : '+852' + digits) : '';

return [{ json: {
  firstName,
  lastName,
  fullName: [firstName, lastName].filter(Boolean).join(' ') || 'Guest',
  email,
  phone,
  waId: phone.replace('+', ''), // WATI needs no + prefix
  service,
  message,
  preferredTime,
  source,
  submittedAt: new Date().toISOString()
} }];

const now = new Date();
const hkOffset = 8 * 60;
const utcMinutes = now.getUTCHours() * 60 + now.getUTCMinutes();
const hkMinutes = (utcMinutes + hkOffset) % (24 * 60);
const hkDay = new Date(now.getTime() + hkOffset * 60000).getUTCDay();

const isWeekday = hkDay >= 1 && hkDay <= 6;
const isOpenHours = hkMinutes >= 540 && hkMinutes < 1140;
const isBusinessHours = isWeekday && isOpenHours;

return [{ json: { ...$input.first().json, isBusinessHours } }];

const emailBody = $input.first().json.choices[0].message.content;
const formData = $('Extract Form Fields').first().json;
const contactId = $('Upsert Contact (Supabase)').first().json[0]?.id;

return [{ json: {
  ...formData,
  contactId,
  emailBody,
  emailSubject: `Thank you for your enquiry — ${formData.service}`,
  htmlBody: '<p>' + emailBody.replace(/\n\n/g, '</p><p>').replace(/\n/g, '<br>') + '</p>'
} }];

// ── CRM ADAPTER ────────────────────────────────────────────
// Edit this node per client to match their CRM field names.
// This node always runs regardless of email/phone availability.
// ────────────────────────────────────────────────────────────

const form = $('Extract Form Fields').first().json;
const leadRow = $('Insert Lead (Supabase)').first().json[0];
const contactRow = $('Upsert Contact (Supabase)').first().json[0];

const crmPayload = {
  source: 'Scalar AI Receptionist',
  channel: 'webform',
  lead_id: leadRow?.id,
  contact_id: contactRow?.id,
  name: form.fullName,
  first_name: form.firstName,
  last_name: form.lastName,
  email: form.email,
  phone: form.phone,
  service_interest: form.service,
  preferred_time: form.preferredTime,
  message: form.message,
  status: 'new',
  captured_at: form.submittedAt
};

const CLIENT_CRM_ENDPOINT = 'YOUR_CLIENT_CRM_WEBHOOK_URL';
const CLIENT_NAME = 'Demo Clinic';

return [{ json: { crmPayload, CLIENT_CRM_ENDPOINT, CLIENT_NAME } }];
